# Illustrative: how vLLM's block table maps logical to physical blocks
# Real implementation is in vllm/core/block_manager.py

from dataclasses import dataclass, field

BLOCK_SIZE = 16   # tokens per physical block

@dataclass
class PhysicalBlock:
    block_id: int
    ref_count: int = 0
    token_ids: list[int] = field(default_factory=list)

class BlockTable:
    """Maps logical block index → physical block for one sequence."""

    def __init__(self):
        self._blocks: list[PhysicalBlock] = []

    def append_block(self, block: PhysicalBlock) -> None:
        block.ref_count += 1
        self._blocks.append(block)

    def physical_block_ids(self) -> list[int]:
        return [b.block_id for b in self._blocks]

    def last_block(self) -> PhysicalBlock | None:
        return self._blocks[-1] if self._blocks else None

    def num_full_blocks(self) -> int:
        return sum(1 for b in self._blocks if len(b.token_ids) == BLOCK_SIZE)


class SimpleBlockAllocator:
    def __init__(self, num_blocks: int):
        self.blocks = {i: PhysicalBlock(i) for i in range(num_blocks)}
        self.free_ids: set[int] = set(range(num_blocks))

    def allocate(self) -> PhysicalBlock:
        if not self.free_ids:
            raise MemoryError("KV-cache OOM")
        bid = self.free_ids.pop()
        return self.blocks[bid]

    def free(self, block: PhysicalBlock) -> None:
        block.ref_count -= 1
        if block.ref_count == 0:
            block.token_ids.clear()
            self.free_ids.add(block.block_id)
